export type LineType = '老阴' | '老阳' | '少阴' | '少阳';

export interface LineData {
  pos: number;
  type: LineType;
  symbol: string;
  stem_branch: string;
  element: string;
  relation: string;
  beast: string;
  is_shi: boolean;
  is_ying: boolean;
  changing_to?: {
    symbol: string;
    stem_branch: string;
    element: string;
    relation: string;
  };
}

export interface HexagramData {
  name: string;
  palace: string;
  palace_element: string;
  lines: LineData[];
}

export interface DivinationResult {
  meta: {
    question: string;
    divination_date: string;
    lunar_date: string;
    method: string;
    day_stem: string;
    day_branch: string;
    month_branch: string;
  };
  rolls_raw: number[];
  hexagram: {
    primary: HexagramData;
    transformed: HexagramData | null;
  };
  analysis_summary: string;
}

export enum FiveElements {
  METAL = '金',
  WOOD = '木',
  WATER = '水',
  FIRE = '火',
  EARTH = '土'
}

export const BRANCH_ELEMENTS: Record<string, string> = {
  '子': '水', '亥': '水',
  '寅': '木', '卯': '木',
  '巳': '火', '午': '火',
  '申': '金', '酉': '金',
  '辰': '土', '戌': '土', '丑': '土', '未': '土'
};

import { FIVE_ELEMENTS_RELATION } from './engine'; // Note: Will move this here or fix cyclic deps

/**
 * Simplified GanZhi calculation for demonstration.
 * In a real app, use a robust lunar calendar library.
 */
export const getGanZhiDate = () => {
  const now = new Date();

  // Stems and Branches
  const stems = ['甲', '乙', '丙', '丁', '戊', '己', '庚', '辛', '壬', '癸'];
  const branches = ['子', '丑', '寅', '卯', '辰', '巳', '午', '未', '申', '酉', '戌', '亥'];

  // This is a very rough estimation for UI purposes. 
  // For precise divination, a real Solar-to-Lunar conversion is required.
  const yearIndex = (now.getFullYear() - 4) % 60;
  const yearStem = stems[yearIndex % 10];
  const yearBranch = branches[yearIndex % 12];

  // Rough Month Branch (Approx based on solar terms)
  const month = now.getMonth(); // 0-indexed
  const monthBranch = branches[(month + 2) % 12];

  // Rough Day Stem/Branch (using 2024-01-01 as base: 甲子)
  const baseDate = new Date(2024, 0, 1);
  const diffDays = Math.floor((now.getTime() - baseDate.getTime()) / (1000 * 3600 * 24));
  const dayStem = stems[diffDays % 10];
  const dayBranch = branches[diffDays % 12];

  return {
    full: `${yearStem}${yearBranch}年 ${monthBranch}月 ${dayStem}${dayBranch}日`,
    yearStem, yearBranch,
    monthBranch,
    dayStem, dayBranch
  };
};

export const getFiveElementRelation = (me: string, other: string) => {
  const relationships: Record<string, Record<string, string>> = {
    '金': { '金': '兄弟', '木': '妻财', '水': '子孙', '火': '官鬼', '土': '父母' },
    '木': { '木': '兄弟', '火': '子孙', '土': '妻财', '金': '官鬼', '水': '父母' },
    '水': { '水': '兄弟', '木': '子孙', '火': '妻财', '土': '官鬼', '金': '父母' },
    '火': { '火': '兄弟', '土': '子孙', '金': '妻财', '水': '官鬼', '木': '父母' },
    '土': { '土': '兄弟', '金': '子孙', '水': '妻财', '木': '官鬼', '火': '父母' }
  };
  return relationships[me][other];
};

import { 
  TRIGRAMS, 
  HEX_DATABASE, 
  SIX_GODS_LIST, 
  DAY_STEM_SIX_GOD_MAP 
} from './constants';
import { 
  LineType, 
  LineData, 
  HexagramData, 
  BRANCH_ELEMENTS 
} from './types';
import { getFiveElementRelation } from './utils';

export const rollToLineType = (roll: number): LineType => {
  if (roll === 1) return '老阴';
  if (roll === 8) return '老阳';
  if (roll >= 2 && roll <= 4) return '少阴';
  return '少阳';
};

export const assembleHexagram = (rolls: number[], dayStem: string): { primary: HexagramData, transformed: HexagramData | null } => {
  const primaryBinary = rolls.map(r => (rollToLineType(r).includes('阴') ? '0' : '1')).join('');
  const primaryInfo = HEX_DATABASE[primaryBinary] || { name: '未知', palace: '未知', shi: 0, ying: 0 };
  const palaceElement = TRIGRAMS[Object.values(TRIGRAMS).find(t => t.name === primaryInfo.palace)?.binary || '111'].element;

  const getNajia = (binary: string): LineData[] => {
    const info = HEX_DATABASE[binary];
    const innerTrigram = TRIGRAMS[binary.substring(0, 3)];
    const outerTrigram = TRIGRAMS[binary.substring(3, 6)];
    const startGodIndex = DAY_STEM_SIX_GOD_MAP[dayStem] || 0;

    return rolls.map((roll, i) => {
      const pos = i + 1;
      const trigram = pos <= 3 ? innerTrigram : outerTrigram;
      const branches = pos <= 3 ? trigram.inner : trigram.outer;
      const branch = branches[i % 3];
      const element = BRANCH_ELEMENTS[branch];
      const type = rollToLineType(roll);

      return {
        pos,
        type,
        symbol: type === '老阳' ? 'O' : type === '老阴' ? 'X' : type === '少阳' ? '——' : '— —',
        stem_branch: branch, // Simplified: just branch for common Najia usage
        element,
        relation: getFiveElementRelation(palaceElement, element),
        beast: SIX_GODS_LIST[(startGodIndex + i) % 6],
        is_shi: info?.shi === pos,
        is_ying: info?.ying === pos
      };
    });
  };

  const primary: HexagramData = {
    name: primaryInfo.name,
    palace: primaryInfo.palace,
    palace_element: palaceElement,
    lines: getNajia(primaryBinary)
  };

  // Transformed
  const hasChange = rolls.some(r => r === 1 || r === 8);
  let transformed: HexagramData | null = null;

  if (hasChange) {
    const transBinary = rolls.map(r => {
      const type = rollToLineType(r);
      if (type === '老阴') return '1';
      if (type === '老阳') return '0';
      return type.includes('阴') ? '0' : '1';
    }).join('');

    const transInfo = HEX_DATABASE[transBinary];
    if (transInfo) {
      // For transformed hexagrams, we often just need the branches of the changing lines
      const transNajia = getNajia(transBinary);
      transformed = {
        name: transInfo.name,
        palace: transInfo.palace,
        palace_element: TRIGRAMS[Object.values(TRIGRAMS).find(t => t.name === transInfo.palace)?.binary || '111'].element,
        lines: transNajia
      };

      // Map transformed branches back to primary lines
      primary.lines.forEach((line, idx) => {
        if (line.type === '老阳' || line.type === '老阴') {
          line.changing_to = {
            symbol: transformed!.lines[idx].symbol,
            stem_branch: transformed!.lines[idx].stem_branch,
            element: transformed!.lines[idx].element,
            relation: getFiveElementRelation(primary.palace_element, transformed!.lines[idx].element)
          };
        }
      });
    }
  }

  return { primary, transformed };
};

import { GoogleGenAI } from "@google/genai";
import { DivinationResult } from "./types";

export const getAIInterpretation = async (data: DivinationResult): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
你是一位精通《京房易》与纳甲六爻预测的资深AI占卜师。
以下是本次起卦的完整排盘信息，请你根据纳甲筮法的核心逻辑，用通俗易懂、带有玄学仪式感的语言为用户解读。

### 卦例背景
- 用户意念：${data.meta.question}
- 占卜时间：${data.meta.lunar_date} (日干支：${data.meta.day_stem}${data.meta.day_branch}，月支：${data.meta.month_branch})

### 排盘信息
- 本卦：${data.hexagram.primary.name} (属${data.hexagram.primary.palace}宫，五行属${data.hexagram.primary.palace_element})
- 变卦：${data.hexagram.transformed?.name || '无变卦'}
- 原始骰点：${data.rolls_raw.join(', ')}

### 详细爻位
${data.hexagram.primary.lines.map(l => `
[${l.pos}爻] ${l.type} ${l.is_shi ? '(世)' : ''} ${l.is_ying ? '(应)' : ''}
    - 纳甲：${l.stem_branch}(${l.element})
    - 六亲：${l.relation}
    - 六神：${l.beast}
    ${l.changing_to ? `- 动变：化${l.changing_to.stem_branch}(${l.changing_to.element}) [${l.changing_to.relation}]` : ''}
`).join('')}

### 解卦指引
1. 定用神：根据问题寻找核心六亲。
2. 论旺衰：参考月建(${data.meta.month_branch})与日辰(${data.meta.day_branch})。
3. 看动变：是否有回头生、回头克。
4. 综合结论：给出明确指引。

请直接输出你的解读文字。
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "大师目前正在冥想中，请稍后再试。";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "天机不可泄露（或网络连接错误），请稍后再问。";
  }
};

import React from 'react';
import { HexagramData, LineData } from '../types';

interface Props {
  data: HexagramData;
  title: string;
}

const HexLine: React.FC<{ line: LineData }> = ({ line }) => {
  const isYang = line.type === '少阳' || line.type === '老阳';
  const isChanging = line.type === '老阴' || line.type === '老阳';

  return (
    <div className="flex items-center justify-between py-2 border-b border-gray-800 hover:bg-gray-900/50 transition-colors">
      <div className="w-12 text-xs text-amber-600 font-bold">{line.beast}</div>
      <div className="w-16 text-sm font-bold text-gray-300">
        {line.relation} {line.stem_branch}
      </div>

      <div className="flex-1 flex flex-col items-center justify-center px-4">
        <div className="relative w-full h-4 flex items-center justify-center">
          {isYang ? (
            <div className={`w-32 h-2 bg-amber-500 rounded-sm ${isChanging ? 'opacity-50' : ''}`} />
          ) : (
            <div className="w-32 flex justify-between">
              <div className={`w-14 h-2 bg-amber-500 rounded-sm ${isChanging ? 'opacity-50' : ''}`} />
              <div className={`w-14 h-2 bg-amber-500 rounded-sm ${isChanging ? 'opacity-50' : ''}`} />
            </div>
          )}
          {isChanging && (
            <div className="absolute inset-0 flex items-center justify-center text-red-500 font-bold text-xl">
              {line.type === '老阳' ? '○' : '×'}
            </div>
          )}
        </div>
      </div>

      <div className="w-16 text-sm flex items-center gap-1">
        {line.is_shi && <span className="bg-red-900 text-white text-[10px] px-1 rounded">世</span>}
        {line.is_ying && <span className="bg-blue-900 text-white text-[10px] px-1 rounded">应</span>}
      </div>

      <div className="w-20 text-xs text-amber-700">
        {line.changing_to && (
          <div className="flex items-center gap-1 animate-pulse">
            <span>→</span>
            <span>{line.changing_to.stem_branch}</span>
            <span>{line.changing_to.relation}</span>
          </div>
        )}
      </div>
    </div>
  );
};

export const HexagramDisplay: React.FC<Props> = ({ data, title }) => {
  return (
    <div className="chinese-border bg-black/40 p-4 rounded-lg">
      <div className="text-center mb-4 border-b border-amber-900 pb-2">
        <h3 className="text-xl font-bold text-amber-500 tracking-widest">{title}</h3>
        <p className="text-xs text-amber-800 uppercase">宫位: {data.palace} | 五行: {data.palace_element}</p>
      </div>
      <div className="flex flex-col-reverse">
        {data.lines.map((line) => (
          <HexLine key={line.pos} line={line} />
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { getGanZhiDate } from './utils';
import { assembleHexagram } from './engine';
import { DivinationResult } from './types';
import { getAIInterpretation } from './geminiService';
import { HexagramDisplay } from './components/HexagramDisplay';

const App: React.FC = () => {
  const [question, setQuestion] = useState('');
  const [isRolling, setIsRolling] = useState(false);
  const [result, setResult] = useState<DivinationResult | null>(null);
  const [aiInterpretation, setAiInterpretation] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [manualInputs, setManualInputs] = useState<string>('');
  const [showManual, setShowManual] = useState(false);

  const startDivination = async (inputRolls?: number[]) => {
    if (!question) {
      alert('请先诚心求问。');
      return;
    }

    setIsRolling(true);
    setAiInterpretation('');

    // Simulate ritual rolling delay
    await new Promise(resolve => setTimeout(resolve, 2000));

    const rolls = inputRolls || Array.from({ length: 6 }, () => Math.floor(Math.random() * 8) + 1);
    const dateInfo = getGanZhiDate();
    const { primary, transformed } = assembleHexagram(rolls, dateInfo.dayStem);

    const divinationResult: DivinationResult = {
      meta: {
        question,
        divination_date: new Date().toLocaleDateString(),
        lunar_date: dateInfo.full,
        method: "Octahedron Dice (d8)",
        day_stem: dateInfo.dayStem,
        day_branch: dateInfo.dayBranch,
        month_branch: dateInfo.monthBranch
      },
      rolls_raw: rolls,
      hexagram: { primary, transformed },
      analysis_summary: transformed ? "动则有变" : "静卦待机"
    };

    setResult(divinationResult);
    setIsRolling(false);

    // Call Gemini for interpretation
    setIsAnalyzing(true);
    const interpretation = await getAIInterpretation(divinationResult);
    setAiInterpretation(interpretation);
    setIsAnalyzing(false);
  };

  const handleManualSubmit = () => {
    const numbers = manualInputs.split(/[,，\s]+/).map(n => parseInt(n)).filter(n => !isNaN(n) && n >= 1 && n <= 8);
    if (numbers.length !== 6) {
      alert('请确保输入6个1-8之间的数字。');
      return;
    }
    startDivination(numbers);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center bg-[url('https://picsum.photos/id/111/1920/1080?grayscale&blur=10')] bg-cover bg-fixed">
      <div className="w-full max-w-4xl bg-black/80 backdrop-blur-md chinese-border rounded-xl p-6 shadow-2xl">

        {/* Header Section */}
        <header className="text-center mb-8">
          <h1 className="text-4xl md:text-6xl font-bold text-amber-500 mb-2 tracking-tighter">八面灵骰 · 六爻神断</h1>
          <p className="text-amber-800 italic">"至诚感天，八卦定乾坤"</p>
          <div className="mt-4 text-sm text-gray-500 border-y border-amber-900/30 py-2 inline-block">
            {getGanZhiDate().full}
          </div>
        </header>

        {/* Input Section */}
        {!result && !isRolling && (
          <div className="max-w-md mx-auto space-y-6">
            <div className="relative">
              <textarea
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
                placeholder="在此输入您的疑惑（如：今日财运、事业发展...）"
                className="w-full h-32 bg-gray-900 border border-amber-900/50 rounded-lg p-4 text-amber-100 placeholder-gray-600 focus:outline-none focus:ring-2 focus:ring-amber-500"
              />
              <div className="absolute -bottom-1 -right-1 text-[100px] opacity-10 pointer-events-none select-none">易</div>
            </div>

            <div className="flex flex-col gap-4">
              <button
                onClick={() => startDivination()}
                className="w-full py-4 bg-amber-700 hover:bg-amber-600 text-white font-bold rounded-lg shadow-lg transform transition active:scale-95 text-xl tracking-widest"
              >
                诚心起卦
              </button>

              <button 
                onClick={() => setShowManual(!showManual)}
                className="text-amber-900 text-sm hover:text-amber-700 transition"
              >
                {showManual ? "隐藏手动输入" : "手动输入点数 (1-8)"}
              </button>

              {showManual && (
                <div className="flex gap-2">
                  <input 
                    type="text"
                    value={manualInputs}
                    onChange={(e) => setManualInputs(e.target.value)}
                    placeholder="例如: 1, 3, 8, 4, 5, 2"
                    className="flex-1 bg-gray-900 border border-amber-900/50 rounded px-3 py-2 text-amber-100"
                  />
                  <button onClick={handleManualSubmit} className="bg-amber-900 px-4 py-2 rounded text-white text-sm">提交</button>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Rolling Animation */}
        {isRolling && (
          <div className="flex flex-col items-center justify-center py-20 space-y-6">
            <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-amber-500 animate-pulse text-lg tracking-[0.5em]">大师正在摒除杂念，演算天机...</p>
          </div>
        )}

        {/* Result Display */}
        {result && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <HexagramDisplay data={result.hexagram.primary} title={`本卦：${result.hexagram.primary.name}`} />
              {result.hexagram.transformed ? (
                <HexagramDisplay data={result.hexagram.transformed} title={`变卦：${result.hexagram.transformed.name}`} />
              ) : (
                <div className="chinese-border bg-black/40 p-4 rounded-lg flex items-center justify-center text-gray-500 italic">
                  此卦为静卦，无动变。
                </div>
              )}
            </div>

            {/* AI Interpretation */}
            <div className="mt-12 bg-gray-900/80 p-6 rounded-xl border-l-4 border-amber-600 relative overflow-hidden">
              <div className="absolute top-0 right-0 opacity-10 transform translate-x-1/4 -translate-y-1/4">
                <svg width="200" height="200" viewBox="0 0 100 100">
                  <circle cx="50" cy="50" r="45" fill="none" stroke="currentColor" strokeWidth="2" />
                  <path d="M50 5 A45 45 0 0 1 50 95 A45 45 0 0 1 50 5 Z" fill="currentColor" opacity="0.2" />
                </svg>
              </div>

              <h2 className="text-2xl font-bold text-amber-500 mb-4 flex items-center gap-2">
                <span className="text-sm bg-amber-600 text-black px-2 py-0.5 rounded">大师解卦</span>
                {result.meta.question}
              </h2>

              <div className="prose prose-invert max-w-none text-gray-300 leading-relaxed whitespace-pre-wrap">
                {isAnalyzing ? (
                  <div className="flex gap-2 items-center text-amber-700 italic">
                    <span className="animate-bounce">●</span>
                    <span className="animate-bounce delay-100">●</span>
                    <span className="animate-bounce delay-200">●</span>
                    大师正在推演五行生克，请稍候...
                  </div>
                ) : (
                  aiInterpretation
                )}
              </div>
            </div>

            {/* JSON Output Tooltip Toggle (Optional debug or expert view) */}
            <div className="mt-8 flex justify-center">
              <button 
                onClick={() => {
                  setResult(null);
                  setQuestion('');
                  setAiInterpretation('');
                }}
                className="px-8 py-2 border border-amber-900 text-amber-900 hover:bg-amber-900 hover:text-white transition rounded-full text-sm"
              >
                重新占卜
              </button>
            </div>

            {/* Expert View: JSON Block */}
            <details className="mt-8 text-xs text-gray-700 cursor-pointer">
              <summary>查看排盘原始数据 (JSON)</summary>
              <pre className="bg-black p-4 rounded mt-2 overflow-auto max-h-48 text-amber-800">
                {JSON.stringify(result, null, 2)}
              </pre>
            </details>
          </div>
        )}
      </div>

      <footer className="mt-8 text-amber-900/50 text-xs">
        &copy; {new Date().getFullYear()} Senior AI Divination Master. 基于《京房易》纳甲筮法。
      </footer>
    </div>
  );
};

export default App;

