export const getAIInterpretation = async (data: DivinationResult): Promise<string> => {
  // Always use a named parameter for apiKey and initialize strictly from process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
你是一位精通《京房易》与纳甲六爻预测的资深AI占卜师。
以下是本次起卦的完整排盘信息，请你根据纳甲筮法的核心逻辑，用通俗易懂、带有玄学仪式感的语言为用户解读。

### 卦例背景
- 用户意念：${data.meta.question}
- 占卜时间：${data.meta.lunar_date} (日干支：${data.meta.day_stem}${data.meta.day_branch}，月支：${data.meta.month_branch})

### 排盘信息
- 本卦：${data.hexagram.primary.name} (属${data.hexagram.primary.palace}宫，五行属${data.hexagram.primary.palace_element})
- 变卦：${data.hexagram.transformed?.name || '无变卦'}
- 原始骰点：${data.rolls_raw.join(', ')}

### 详细爻位
${data.hexagram.primary.lines.map(l => `
[${l.pos}爻] ${l.type} ${l.is_shi ? '(世)' : ''} ${l.is_ying ? '(应)' : ''}
    - 纳甲：${l.stem_branch}(${l.element})
    - 六亲：${l.relation}
    - 六神：${l.beast}
    ${l.changing_to ? `- 动变：化${l.changing_to.stem_branch}(${l.changing_to.element}) [${l.changing_to.relation}]` : ''}
`).join('')}

### 解卦指引
1. 定用神：根据问题寻找核心六亲。
2. 论旺衰：参考月建(${data.meta.month_branch})与日辰(${data.meta.day_branch})。
3. 看动变：是否有回头生、回头克。
4. 综合结论：给出明确指引。

请直接输出你的解读文字。
`;

  try {
    // Correct usage of generateContent for text tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
