import React, { useState, useEffect } from 'react';

interface Props {
  rolls: number[];
  onComplete: () => void;
}

const D8Icon = ({ value, isRolling }: { value: number; isRolling: boolean }) => (
  <div className={`relative w-16 h-16 flex items-center justify-center transition-all duration-500 ${isRolling ? 'animate-bounce scale-110' : 'scale-100'}`}>
    <svg viewBox="0 0 100 100" className={`w-full h-full ${isRolling ? 'text-amber-900/50' : 'text-amber-500'}`} fill="currentColor">
      {/* Octahedron front view simplified */}
      <path d="M50 5 L90 50 L50 95 L10 50 Z" opacity="0.8" />
      <path d="M50 5 L50 95" stroke="black" strokeWidth="1" opacity="0.3" />
      <path d="M10 50 L90 50" stroke="black" strokeWidth="1" opacity="0.3" />
    </svg>
    {!isRolling && (
      <span className="absolute text-2xl font-bold text-black drop-shadow-md">{value}</span>
    )}
  </div>
);

export const DiceRollingEffect: React.FC<Props> = ({ rolls, onComplete }) => {
  const [visibleCount, setVisibleCount] = useState(0);

  useEffect(() => {
    if (visibleCount < 6) {
      const timer = setTimeout(() => {
        setVisibleCount(prev => prev + 1);
      }, 600); // Reveal each die every 600ms
      return () => clearTimeout(timer);
    } else {
      const timer = setTimeout(onComplete, 1000); // Finish 1s after last die
      return () => clearTimeout(timer);
    }
  }, [visibleCount, onComplete]);

  return (
    <div className="flex flex-col items-center justify-center space-y-8 py-10">
      <div className="text-amber-600 text-lg tracking-[0.3em] font-bold mb-4 animate-pulse">
        天机流转，灵骰定象
      </div>

      <div className="flex flex-col-reverse gap-4">
        {[0, 1, 2, 3, 4, 5].map((idx) => {
          const isSettled = visibleCount > idx;
          const isCurrentlyRolling = visibleCount === idx;

          return (
            <div key={idx} className="flex items-center gap-6">
              <span className="text-amber-900/40 text-xs w-12">第{idx + 1}爻</span>
              <div className={`w-20 h-20 flex items-center justify-center rounded-full border-2 border-dashed transition-all duration-300 ${isSettled ? 'border-amber-500 bg-amber-500/10' : 'border-amber-900/20'}`}>
                {isSettled ? (
                  <D8Icon value={rolls[idx]} isRolling={false} />
                ) : isCurrentlyRolling ? (
                  <D8Icon value={Math.floor(Math.random() * 8) + 1} isRolling={true} />
                ) : (
                  <div className="w-4 h-4 rounded-full bg-amber-900/10" />
                )}
              </div>
              <div className="w-24">
                {isSettled && (
                  <span className="text-amber-500 font-bold animate-in fade-in slide-in-from-left-2">
                    {rolls[idx] === 1 ? '老阴 X' : rolls[idx] === 8 ? '老阳 O' : rolls[idx] < 5 ? '少阴' : '少阳'}
                  </span>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

