export const getAIInterpretation = async (data: DivinationResult): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `你是一位精通《京房易》与纳甲六爻预测的资深卦师。
你的解读准则：
1. **客观真实**：卦象显示的吉凶必须如实相告。如果是凶卦（如：用神月破、日克、回头克），严禁为了安慰用户而编造好话。凶即是凶，吉即是吉。
2. **具象化建议**：避免堆砌玄奥晦涩的术语。将“官鬼克世”翻译成具体的“职场压力、小人作祟或身体不适”；将“妻财旺相”翻译成具体的“财源广进或求财得利”。
3. **逻辑严密**：必须根据提供的“月建（月支）”和“日辰（日支）”来判断用神的旺衰。考虑长生十二神、旬空、月破、日冲等要素。
4. **仪式感与权威感**：语气沉稳、专业，像一位历经沧桑且不妄语的智者。
5. **结构清晰**：先给总论（吉/凶/平），再分点阐述核心依据，最后给出具体的行动指引。`;

  const prompt = `
### 占卜请求
- **求问之事**：${data.meta.question}
- **时间背景**：${data.meta.lunar_date}（月建：${data.meta.month_branch}，日辰：${data.meta.day_branch}）

### 完整排盘
- **本卦**：${data.hexagram.primary.name}（宫位：${data.hexagram.primary.palace}，五行：${data.hexagram.primary.palace_element}）
- **变卦**：${data.hexagram.transformed?.name || '无'}
- **排盘详情**：
${data.hexagram.primary.lines.map(l => {
  let lineDesc = `[${l.pos}爻] ${l.relation}${l.stem_branch}(${l.element}) - ${l.beast}${l.is_shi ? ' (世爻)' : ''}${l.is_ying ? ' (应爻)' : ''}`;
  if (l.changing_to) {
    lineDesc += ` -> 动化${l.changing_to.relation}${l.changing_to.stem_branch}(${l.changing_to.element})`;
  }
  return lineDesc;
}).join('\n')}

### 任务要求
请基于以上信息，判定用神，分析月破、日建、动变之影响，给出一份言简意赅、客观真实的解卦报告。`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Using Pro for more rigorous reasoning
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7,
        topP: 0.9,
      }
    });

    return response.text || "卦辞隐晦，天机暂不可测。";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "断卦时灵气波动，请稍后再试。";
  }
};

