            {getGanZhiDate().full}
          </div>
        </header>

        <main className="modern-card rounded-[2.5rem] p-8 md:p-12 transition-all duration-500 min-h-[500px]">
          {!result && !isRolling && (
            <div className="flex flex-col items-center space-y-8 animate-in fade-in duration-700">
              <div className="w-full max-w-lg">
                <label className="block text-sm font-bold text-slate-500 mb-2 ml-1">你想知道什么？</label>
                <textarea
                  value={question}
                  onChange={(e) => setQuestion(e.target.value)}
