                  className="w-full h-32 bg-slate-50 border-2 border-slate-100 rounded-3xl p-6 text-lg text-slate-800 placeholder-slate-300 focus:outline-none focus:border-blue-400 focus:ring-4 focus:ring-blue-50 transition-all resize-none shadow-inner"
